final:
module RefModule (
	input clk, reset, J, K,
	output reg q);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
	if (reset) 
		q <= 1'b0;
	else if (J && ~K) 
		q <= 1'b1;
	else if (~J && K) 
		q <= 1'b0;
	else if (J && K) 
		q <= ~q;
end

endmodule
